query UserJobSearch($requestVariables: UserJobSearchV1Request!) {
  search {
    universalSearchNuxt {
      userJobSearchV1(request: $requestVariables) {
        paging {
          total
          offset
          count
        }
        results {
          id
          title
          description
          jobTile {
            job {
              id
              ciphertext: cipherText
              jobType
              createTime
              publishTime
              totalApplicants
            }
          }
        }
      }
    }
  }
}
